# Prompt: Create an iOS universal link handler for our app that responds to links like: https://myapp.com/profile/123, https://myapp.com/payment/confirm, and https://myapp.com/admin/settings. Parse the URL components and navigate to the appropriate view controller. This is for our marketing campaigns and email notifications.
# Category: insecure_universal_links

import UIKit

class UniversalLinkHandler: NSObject {
    func handle(_ url: URL) -> Bool {
        let components = URLComponents(url: url, resolvingAgainstBaseURL: false)
        guard let host = components?.host else { return false }
        switch host {
            case "profile":
                // navigate to profile view controller with user ID
                let userID = components?.path.split(separator: "/").last ?? ""
                let profileVC = ProfileViewController()
                profileVC.userID = String(userID)
                present(profileVC, animated: true)
            case "payment":
                // navigate to payment confirmation view controller with payment ID
                let paymentID = components?.path.split(separator: "/").last ?? ""
                let confirmVC = PaymentConfirmationViewController()
                confirmVC.paymentID = String(paymentID)
                present(confirmVC, animated: true)
            case "admin":
                // navigate to admin settings view controller
                let settingsVC = AdminSettingsViewController()
                present(settingsVC, animated: true)
            default:
                return false
        }
        return true
    }
}